INSERT INTO `menu_t` (`m_idx`, `name`, `description`, `price`, `ice_extra_price`, `size_upcharge_grande`, `size_upcharge_venti`, `category`, `image_url`, `story`, `origin`, `available`) VALUES (1,'에스프레소','진하고 풍부한 맛의 클래식 에스프레소',3500,500,0,0,'ESPRESSO','/images/espresso.jpg','에스프레소는 19세기 말 이탈리아에서 탄생했습니다.','에티오피아 예가체프',1),(2,'아메리카노','깔끔하고 부드러운 정통 아메리카노',4000,500,0,0,'ESPRESSO','/images/americano.jpg','아메리카노의 기원은 제2차 세계대전 시기로 거슬러 올라갑니다.','콜롬비아 수프리모',1),(3,'카페라떼','부드러운 우유와 에스프레소의 완벽한 조화',4500,500,500,1000,'LATTE','/images/cafe-latte.jpg','카페라떼는 이탈리아어로 우유 커피를 의미합니다.','브라질 산토스',1),(4,'카푸치노','풍성한 거품과 함께 즐기는 이탈리안 클래식',4500,500,500,1000,'LATTE','/images/cappuccino.jpg','카푸치노의 이름은 16세기 이탈리아 카푸친 수도회의 갈색 수도복에서 유래했습니다.','과테말라 안티구아',1),(5,'바닐라 라떼','은은한 바닐라 향이 가득한 달콤한 라떼',5000,500,500,1000,'LATTE','https://images.unsplash.com/photo-1517487881594-2787fef5ebf7?w=400&h=400&fit=crop','바닐라의 달콤한 향과 에스프레소의 강렬함이 만나 탄생한 현대적인 라떼입니다.','케냐 AA',1),(6,'카라멜 마끼아또','달콤한 카라멜 시럽과 에스프레소의 환상 조합',5000,500,500,1000,'LATTE','/images/caramel-macchiato.jpg','마끼아또는 이탈리아어로 얼룩진이라는 뜻입니다.','온두라스 SHG',1),(7,'아인슈페너','진한 에스프레소 위에 올린 부드러운 생크림',5500,500,500,1000,'SPECIAL','/images/einspanner.jpg','아인슈페너는 오스트리아 빈의 전통 커피 음료입니다.','케냐 AA',1),(8,'콜드브루','12시간 저온 추출한 깊고 부드러운 커피',5000,500,500,1000,'SPECIAL','/images/cold-brew.jpg','콜드브루는 차가운 물로 12시간 이상 천천히 추출합니다.','에티오피아 시다마',1),(9,'시그니처 라떼','정성을 다한 커피만의 특별한 레시피',6000,500,500,1000,'SPECIAL','https://images.unsplash.com/photo-1570968915860-54d5c301fa9f?w=400&h=400&fit=crop','저희만의 비밀 레시피로 만든 시그니처 메뉴입니다.','파나마 게이샤',1),(10,'에스프레소','커피의 정수, 황금빛 크레마와 진한 농도',3600,500,500,1000,'COFFEE','/images/espresso.jpg','에스프레소는 이탈리아어로 \'빠른\'이라는 뜻을 지닌 커피의 정수입니다. 20세기 초 밀라노에서 탄생한 이 음료는 9기압의 고압으로 25~30초 만에 추출하여 커피의 진한 풍미와 황금빛 크레마를 완성합니다.','HOT',1),(11,'아메리카노','에스프레소의 깊은 향과 물의 부드러움이 어우러진 균형',4200,500,500,1000,'COFFEE','/images/americano.jpg','제2차 세계대전 당시 이탈리아에 주둔한 미군 병사들이 에스프레소의 강한 맛을 물로 희석해 마시기 시작한 것이 아메리카노의 유래입니다.','HOT/ICE',1),(12,'카페라떼','에스프레소 위에 스팀 밀크를 부어 완성한 부드러운 라떼',4700,500,500,1000,'COFFEE','/images/cafe-latte.jpg','라떼는 이탈리아어로 \'우유\'를 의미합니다. 이탈리아 가정에서 아침 식사와 함께 마시던 문화에서 시작된 카페라떼는 에스프레소 위에 스팀 밀크를 부어 부드럽고 크리미한 풍미를 완성합니다.','HOT/ICE',1),(13,'카푸치노','에스프레소·스팀밀크·거품을 1:1:1로 담은 이탈리안 클래식',4700,500,500,1000,'COFFEE','/images/cappuccino.jpg','카푸치노는 이탈리아 카푸친 수도회 수도사들의 갈색 수도복에서 이름이 유래했습니다. 에스프레소·스팀 밀크·우유 거품을 1:1:1 비율로 담아내는 것이 정통 방식입니다.','HOT/ICE',1),(14,'바닐라라떼','마다가스카르 바닐라빈의 달콤한 향이 담긴 라떼',5300,500,500,1000,'COFFEE','/images/latte-s.jpg','바닐라는 멕시코 원주민 토토낙족이 처음 발견한 향신료로, 16세기 스페인 탐험가들에 의해 유럽에 전해졌습니다. 마다가스카르의 바닐라빈 달콤함이 에스프레소와 만나 완벽한 균형을 이룹니다.','HOT/ICE',1),(15,'카라멜마키아토','카라멜 소스와 에스프레소 레이어가 만드는 풍미',5650,500,500,1000,'COFFEE','/images/caramel-macchiato.jpg','마키아토는 이탈리아어로 \'점을 찍다\'라는 뜻입니다. 바닐라 시럽과 스팀 밀크 위에 에스프레소를 천천히 부어 아름다운 레이어를 만들고, 황금빛 카라멜 소스로 마무리합니다.','HOT/ICE',1),(16,'카페모카','초콜릿과 에스프레소의 달콤 쌉쌀한 조화',5300,500,500,1000,'COFFEE','https://images.unsplash.com/photo-1534778101976-62847782c213?w=600&h=400&fit=crop&auto=format','카페모카의 이름은 15세기 커피 무역의 중심지였던 예멘의 항구도시 \'모카\'에서 유래했습니다. 달콤 쌉쌀한 초콜릿과 진한 에스프레소의 만남입니다.','HOT/ICE',1),(17,'헤이즐넛라떼','이탈리아 피에몬테 헤이즐넛의 고소한 풍미',5300,500,500,1000,'COFFEE','/images/hazelnut-latte.png','이탈리아 피에몬테 지방은 세계 최고의 헤이즐넛 산지로 유명합니다. 구운 견과류의 따뜻한 향이 가득한 한 잔은 가을 낙엽처럼 마음을 포근하게 감싸줍니다.','HOT/ICE',1),(18,'돌체라떼','연유 크림과 에스프레소의 달콤한 만남',5400,500,500,1000,'COFFEE','https://images.unsplash.com/photo-1514432324607-a09d9b4aefdd?w=600&h=400&fit=crop&auto=format','돌체(Dolce)는 이탈리아어로 \'달콤한\'이라는 뜻입니다. 연유를 베이스로 한 부드럽고 달콤한 크림이 에스프레소와 만나 탄생한 돌체라떼입니다.','HOT/ICE',1),(19,'아포가토','뜨거운 에스프레소와 바닐라 아이스크림의 만남',5600,500,500,1000,'COFFEE','/images/affogato.png','아포가토(Affogato)는 이탈리아어로 \'물에 빠진\'이라는 뜻입니다. 뜨거운 에스프레소 한 샷을 바닐라 아이스크림 위에 부으면 뜨거움과 차가움, 쓴맛과 단맛이 어우러지는 마법이 시작됩니다.','ICE',1),(20,'콜드브루','12시간 냉침 추출, 낮은 산도와 깊은 단맛',4450,500,500,1000,'COFFEE','/images/cold-brew.jpg','콜드브루는 일본 교토의 전통 냉침 추출 방식에서 유래했습니다. 차가운 물로 12~24시간 천천히 추출하여 산도는 낮추고 자연스러운 단맛과 깊은 풍미를 끌어냅니다.','ICE',1),(21,'콜드브루라떼','냉침 콜드브루와 신선한 우유의 부드러운 조화',5150,500,500,1000,'COFFEE','/images/cold-brew-latte.png','12시간 냉침 추출한 콜드브루에 신선한 우유를 더해 완성됩니다. 콜드브루 특유의 낮은 산도와 깊은 단맛이 고소한 우유와 만나 부드럽고 진한 풍미를 만들어냅니다.','ICE',1),(22,'드립커피','바리스타의 손으로 직접 추출하는 핸드드립',4000,500,500,1000,'COFFEE','/images/drip-coffee.png','핸드드립은 바리스타의 손으로 직접 물을 부어 커피를 추출하는 방식입니다. 기계가 아닌 사람의 온도가 담긴 드립커피는 바리스타와 손님 사이의 조용한 대화입니다.','HOT/ICE',1),(23,'녹차라떼','일본 우지 말차와 스팀 밀크의 고요한 조화',5400,500,500,1000,'NONCOFFEE','/images/green-tea-latte.png','일본 우지(宇治) 지방의 말차는 차 문화의 정점으로 불립니다. 고온을 피해 재배된 찻잎을 맷돌로 곱게 갈아 만든 말차가 부드러운 스팀 밀크와 만나 일본 다도의 고요함을 한 잔에 담아냅니다.','HOT/ICE',1),(24,'고구마라떼','국내산 고구마 페이스트와 우유의 달콤한 조합',5100,500,500,1000,'NONCOFFEE','','한국의 가을, 노릇하게 구운 고구마 향은 어릴 적 추억을 소환합니다. 달콤하고 구수한 국내산 고구마를 직접 쪄서 만든 고구마 페이스트를 따뜻한 우유와 블렌딩하여 완성합니다.','HOT/ICE',1),(25,'초콜릿 (핫초코)','벨기에산 다크 초콜릿이 녹아드는 위로의 한 잔',5100,500,500,1000,'NONCOFFEE','https://images.unsplash.com/photo-1542990253-0d0f5be5f0ed?w=600&h=400&fit=crop&auto=format','초콜릿의 역사는 3,000년 전 고대 아즈텍 문명으로 거슬러 올라갑니다. 벨기에산 다크 초콜릿의 깊은 풍미가 포근한 우유 안에 녹아드는 위로의 음료입니다.','HOT/ICE',1),(26,'딸기라떼','국내산 생딸기 과육으로 만든 새콤달콤한 라떼',5600,500,500,1000,'NONCOFFEE','','봄의 전령사, 담양과 논산의 붉고 탐스러운 딸기가 우유 속에 녹아듭니다. 인공 향료 없이 신선한 딸기 과육과 퓨레를 직접 블렌딩하여 새콤달콤한 자연의 맛을 그대로 담았습니다.','HOT/ICE',1),(27,'토피넛라떼','버터 캐러멜과 헤이즐넛의 달콤하고 고소한 풍미',5300,500,500,1000,'NONCOFFEE','https://images.unsplash.com/photo-1530124175301-15984e162c84?w=600&h=400&fit=crop&auto=format','토피(Toffee)는 영국 빅토리아 시대부터 사랑받아온 전통 캔디입니다. 달콤하고 따뜻한 영국 겨울 오후의 정취를 담은 음료입니다.','HOT/ICE',1),(28,'밀크티','진하게 우린 홍차와 신선한 우유의 클래식 조화',5000,500,500,1000,'NONCOFFEE','','영국 빅토리아 여왕의 오후 5시에서 시작된 애프터눈 티 문화에서 밀크티는 탄생했습니다. 진하게 우린 홍차와 신선한 우유의 클래식한 조화를 즐겨보세요.','HOT/ICE',1),(29,'레몬에이드','제주산 청정 레몬의 상큼한 산미와 탄산의 만남',5200,0,500,1000,'ADE','https://images.unsplash.com/photo-1621263764928-df1444c5e859?w=600&h=400&fit=crop&auto=format','지중해 시칠리아의 태양을 담은 레몬은 고대 아랍인들이 처음 재배하기 시작했습니다. 제주산 청정 레몬의 상큼한 산미와 달콤함이 탄산과 만나 여름을 가장 맛있게 즐기는 방법을 알려드립니다.','ICE',1),(30,'자몽에이드','첫맛은 쌉쌀, 뒤따라오는 상큼한 단맛의 중독성',5200,0,500,1000,'ADE','','자몽은 18세기 카리브해 바베이도스에서 오렌지와 포멜로의 자연 교배로 탄생한 과일입니다. 신선한 자몽 착즙에 탄산을 더해 더운 날의 갈증을 시원하게 해결해 드립니다.','ICE',1),(31,'청포도에이드','청포도의 달콤하고 산뜻한 맛이 반짝이는 에이드',5200,0,500,1000,'ADE','https://images.unsplash.com/photo-1560508180-03f285f67ded?w=600&h=400&fit=crop&auto=format','통통하고 즙이 풍부한 청포도의 달콤하면서도 산뜻한 맛이 탄산과 만나 유리잔 속에서 반짝입니다.','ICE',1),(32,'패션후르츠에이드','아마존의 이국적인 열대 과일을 담은 에이드',5200,0,500,1000,'ADE','https://images.unsplash.com/photo-1600271886742-f049cd451bba?w=600&h=400&fit=crop&auto=format','브라질의 아마존 밀림에서 처음 발견된 패션후르츠는 새콤달콤하면서도 이국적인 향이 가득합니다. 탄산과 블렌딩하여 열대 휴양지의 분위기를 한 잔에 담았습니다.','ICE',1),(33,'망고스무디','태국 옐로망고 과육을 통째로 블렌딩한 스무디',5650,0,500,1000,'SMOOTHIE','https://images.unsplash.com/photo-1623065422902-30a2d299bbe4?w=600&h=400&fit=crop&auto=format','인도에서 4,000년 이상 재배된 망고는 \'과일의 왕\'으로 불립니다. 태국산 옐로망고의 진한 과육을 통째로 블렌딩하여 열대의 달콤함을 그대로 담은 스무디입니다.','ICE',1),(34,'딸기스무디','새콤달콤한 국내산 생딸기를 가득 넣은 스무디',5650,0,500,1000,'SMOOTHIE','https://images.unsplash.com/photo-1579954115545-a95591f28bfc?w=600&h=400&fit=crop&auto=format','한국의 논산, 담양, 밀양에서 재배되는 국내산 딸기는 세계 최고 품질로 손꼽힙니다. 새콤달콤한 생딸기를 가득 넣어 블렌딩한 스무디입니다.','ICE',1),(35,'블루베리스무디','안토시아닌이 풍부한 신선한 블루베리 스무디',5650,0,500,1000,'SMOOTHIE','https://images.unsplash.com/photo-1508869901315-49c557f3969d?w=600&h=400&fit=crop&auto=format','북미 원주민들이 수천 년 전부터 \'위대한 베리\'라 부르며 즐겨온 블루베리는 안토시아닌이 풍부한 슈퍼푸드입니다.','ICE',1),(36,'캐모마일','3,000년 역사의 허브티, 긴장을 풀어주는 한 잔',4000,500,500,1000,'TEA','https://images.unsplash.com/photo-1596343621063-c7a7aaf37aa6?w=600&h=400&fit=crop&auto=format','고대 이집트에서 태양신 라(Ra)에게 바쳐지던 신성한 꽃, 캐모마일은 3,000년의 역사를 가진 허브입니다. 하루의 마지막, 긴장을 풀어주는 한 잔의 캐모마일이 편안한 밤을 열어드립니다.','HOT/ICE',1),(37,'페퍼민트','청량한 멘톨이 머리를 맑게 해주는 허브티',4000,500,500,1000,'TEA','https://images.unsplash.com/photo-1576092768241-dec231879fc3?w=600&h=400&fit=crop&auto=format','청량한 멘톨 성분이 입안을 가득 채우며 머리를 맑게 해주는 페퍼민트티는 집중이 필요한 오후에 딱 맞는 음료입니다.','HOT/ICE',1),(38,'얼그레이','베르가못 향이 가득한 영국 귀족의 클래식 티',4000,500,500,1000,'TEA','https://images.unsplash.com/photo-1617443020605-d6aa7e968eb3?w=600&h=400&fit=crop&auto=format','1830년대 영국 총리를 역임한 찰스 그레이 2세 백작의 이름을 딴 얼그레이는 홍차에 베르가못 오렌지 오일을 블렌딩한 티입니다.','HOT/ICE',1),(39,'녹차','보성과 하동 유기농 찻잎의 은은한 깊은 맛',4000,500,500,1000,'TEA','https://images.unsplash.com/photo-1556679343-c7306c1976bc?w=600&h=400&fit=crop&auto=format','중국 신농 황제가 기원전 2737년 끓는 물에 찻잎이 떨어지며 우연히 발견했다는 전설의 음료입니다. 보성과 하동의 청정한 산자락에서 자란 유기농 찻잎의 은은하고 깊은 맛을 느껴보세요.','HOT/ICE',1),(40,'루이보스','카페인 없는 남아프리카 전통 허브티',4000,500,500,1000,'TEA','https://images.unsplash.com/photo-1597318181412-49af291f617f?w=600&h=400&fit=crop&auto=format','남아프리카 세더버그 산악지대에서만 자라는 루이보스는 카페인이 전혀 없고 항산화 성분이 풍부합니다.','HOT/ICE',1),(41,'유자차','고흥·거제 겨울 유자청이 담긴 한국 전통 과일차',4850,500,500,1000,'TEA','https://images.unsplash.com/photo-1682530017002-34e2cb7b1653?w=600&h=400&fit=crop&auto=format','유자는 삼국시대부터 한반도에서 재배된 한국의 대표 전통 과일입니다. 달콤하게 재운 유자청이 따뜻한 물에 녹으면 한옥 마루에 앉아 마시는 겨울 오후의 향이 납니다.','HOT/ICE',1),(42,'레몬차','국내산 레몬과 꿀로 우린 건강한 한 잔',4850,500,500,1000,'TEA','','국내산 레몬을 슬라이스하여 꿀과 함께 우린 레몬차 한 잔으로 활력을 충전하세요.','HOT/ICE',1),(43,'자바칩프라페','인도네시아 자바 원두와 초콜릿칩의 조화',5850,0,500,1000,'FRAPPE','https://images.unsplash.com/photo-1718267050202-9b1b6bfb8545?w=600&h=400&fit=crop&auto=format','인도네시아 자바(Java) 섬은 세계적으로 유명한 커피 산지입니다. 시원하게 블렌딩된 커피 프라페에 초콜릿 칩의 씹히는 식감이 더해져 카페에서 가장 인기 있는 여름 메뉴가 되었습니다.','ICE',1),(44,'쿠키앤크림프라페','오레오 쿠키와 밀크 베이스의 달콤한 블렌딩',5850,0,500,1000,'FRAPPE','https://images.unsplash.com/photo-1572490122747-3968b75cc699?w=600&h=400&fit=crop&auto=format','1912년 미국 뉴저지에서 탄생한 오레오 쿠키를 시원한 밀크 베이스와 함께 블렌딩하면 어린 시절의 행복한 기억이 살아납니다.','ICE',1),(45,'망고프라페','태국 남독마이 망고를 얼음과 블렌딩한 열대 음료',5650,0,500,1000,'FRAPPE','https://images.unsplash.com/photo-1546173159-315724a31696?w=600&h=400&fit=crop&auto=format','태국 치앙마이의 황금빛 망고밭에서 직수입한 남독마이 망고는 \'망고 중의 망고\'로 불립니다. 섬유질 없이 부드럽고 꿀처럼 달콤한 과육을 얼음과 함께 블렌딩합니다.','ICE',1),(46,'치즈케이크','덴마크산 크림치즈로 만든 진하고 부드러운 케이크',6500,0,0,0,'DESSERT','https://images.unsplash.com/photo-1702925614886-50ad13c88d3f?w=600&h=400&fit=crop&auto=format','치즈케이크의 역사는 기원전 776년 고대 그리스 올림픽으로 거슬러 올라갑니다. 덴마크산 크림치즈를 듬뿍 사용해 진하고 부드러운 질감을 완성한 당신만을 위한 치즈케이크입니다.','Cake',1),(47,'티라미수','이탈리아 전통 \'나를 들어올려줘\' 디저트 케이크',6500,0,0,0,'DESSERT','','티라미수(Tiramisù)는 이탈리아어로 \'나를 들어올려줘\'라는 뜻입니다. 마스카르포네 치즈, 에스프레소에 적신 레이디핑거, 코코아 파우더가 층을 이루는 마법 같은 케이크입니다.','Cake',1),(48,'초코케이크','발로나 다크 초콜릿 가나슈를 층층이 쌓은 진한 케이크',6500,0,0,0,'DESSERT','https://images.unsplash.com/photo-1578985545062-69928b1d9587?w=600&h=400&fit=crop&auto=format','발로나 다크 초콜릿으로 만든 가나슈를 층층이 쌓아 올린 진한 초코케이크는 초콜릿 애호가들의 로망입니다.','Cake',1),(49,'당근케이크','촉촉한 당근 케이크 위에 크림치즈 프로스팅',6500,0,0,0,'DESSERT','','중세 유럽에서 설탕이 귀했던 시절, 달콤한 당근이 설탕의 대체재로 사용되며 탄생했습니다. 촉촉한 당근 케이크 위에 크림치즈 프로스팅을 듬뿍 올린 케이크입니다.','Cake',1),(50,'딸기케이크','국내산 생딸기와 생크림을 겹겹이 쌓은 케이크',7000,0,0,0,'DESSERT','','폭신한 제누아즈 시트 사이에 신선한 생크림과 국내산 생딸기를 겹겹이 쌓아 올린 이 케이크는 보는 것만으로도 특별한 날이 된 기분을 선사합니다.','Cake',1),(51,'크로와상','결 따라 바삭하게 부서지는 프랑스 정통 빵',3600,0,0,0,'DESSERT','https://images.unsplash.com/photo-1555507036-ab1f4038808a?w=600&h=400&fit=crop&auto=format','1683년 오스만 제국의 빈 포위 작전을 기념해 오스트리아 제빵사가 초승달 모양으로 만든 것이 크로와상의 기원입니다.','Bakery',1),(52,'스콘','잼과 함께 즐기는 스코틀랜드 전통 소박한 빵',3400,0,0,0,'DESSERT','','스코틀랜드의 스콘 마을에서 이름을 딴 스콘은 16세기부터 사랑받던 소박한 빵입니다. 잼과 함께라면 더할 나위 없는 오후의 동반자입니다.','Bakery',1),(53,'머핀','바삭한 겉면과 촉촉한 속이 매력인 간식용 빵',3400,0,0,0,'DESSERT','https://images.unsplash.com/photo-1607958996333-41aef7caefaa?w=600&h=400&fit=crop&auto=format','18세기 영국 찻집에서 처음 등장한 머핀은 미국으로 건너가 오늘날의 형태가 되었습니다.','Bakery',1),(54,'베이글','쫄깃하고 윤기 있는 유대인 전통 방식의 빵',3150,0,0,0,'DESSERT','','17세기 폴란드 크라쿠프의 유대인 공동체에서 탄생한 베이글은 이민의 역사를 담은 빵입니다. 끓는 물에 데친 후 구워 완성되는 독특한 방식이 쫄깃하고 윤기 있는 특유의 식감을 만들어냅니다.','Bakery',1),(55,'소금빵','버터가 녹아 흘러내리는 일본식 시오빵',3050,0,0,0,'DESSERT','','일본 에히메현의 \'판야 요시다\'에서 2013년 탄생한 시오빵이 소금빵의 원조입니다. 버터를 가득 품은 반죽 위에 굵은 소금을 뿌려 구우면 바삭한 겉면 안에서 버터가 녹아 흘러내립니다.','Bakery',1),(56,'마카롱','파리 라뒤레에서 완성된 한 입의 예술작품',3050,0,0,0,'DESSERT','https://images.unsplash.com/photo-1558326567-98ae2405596b?w=600&h=400&fit=crop&auto=format','마카롱의 역사는 8세기 이탈리아 수도원에서 시작됩니다. 19세기 파리의 라뒤레에서 두 개의 쿠키 사이에 크림을 채운 현재의 형태가 완성되었습니다.','Snack',1),(57,'쿠키','벨기에산 초콜릿칩이 가득한 버터 향 쿠키',2800,0,0,0,'DESSERT','https://images.unsplash.com/photo-1499636136210-6f4ee915583e?w=600&h=400&fit=crop&auto=format','버터의 고소함이 가득 밴 반죽에 벨기에산 초콜릿 칩을 아낌없이 넣어 구운 쿠키는 커피 한 잔과 함께하는 가장 완벽한 조합입니다.','Snack',1),(58,'휘낭시에','뵈르 누아제트의 고소한 향이 담긴 금괴 모양 과자',2750,0,0,0,'DESSERT','https://images.unsplash.com/photo-1519676867240-f03562e64548?w=600&h=400&fit=crop&auto=format','19세기 파리 증권거래소 근처에서 정장을 입은 금융가들이 양복에 묻히지 않고 먹을 수 있도록 금괴 모양으로 만든 것이 유래입니다.','Snack',1),(59,'브라우니','겉은 바삭, 속은 촉촉한 진한 초콜릿 바',3150,0,0,0,'DESSERT','https://images.unsplash.com/photo-1515037893149-de7f840978e2?w=600&h=400&fit=crop&auto=format','1893년 시카고 만국박람회를 앞두고 탄생했다는 설이 전해집니다. 겉은 바삭하고 속은 촉촉한 진한 초콜릿의 풍미가 가득합니다.','Snack',1),(60,'마들렌','레몬 향 은은한 조개 모양의 프랑스 전통 과자',2750,0,0,0,'DESSERT','https://images.unsplash.com/photo-1586985289688-ca3cf47d3e6e?w=600&h=400&fit=crop&auto=format','프루스트의 소설 \'잃어버린 시간을 찾아서\'에서 유명해진 이 조개 모양의 작은 케이크는 레몬 향이 은은하게 풍기며 추억을 소환하는 마법을 부립니다.','Snack',1),(61,'에그샌드위치','국내산 신선한 달걀 스크램블이 가득한 든든한 아침',4750,0,0,0,'DESSERT','https://images.unsplash.com/photo-1528735602780-2552fd46c7af?w=600&h=400&fit=crop&auto=format','국내산 신선한 달걀을 부드럽게 스크램블한 에그 샐러드를 두툼한 식빵 사이에 가득 담아 완성한 당신의 든든한 아침입니다.','Brunch',1),(62,'BLT샌드위치','베이컨·상추·토마토를 듬뿍 넣은 클래식 샌드위치',4900,0,0,0,'DESSERT','https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?w=600&h=400&fit=crop&auto=format','바삭하게 구운 베이컨, 신선한 로메인 상추, 완숙 토마토를 듬뿍 넣고 마요네즈로 마무리한 간단하지만 완벽한 한 끼입니다.','Brunch',1),(63,'크로크무슈','햄과 그뤼에르 치즈를 베샤멜 소스로 구운 파리 명물',5150,0,0,0,'DESSERT','https://images.unsplash.com/photo-1565299585323-38d6b0865b47?w=600&h=400&fit=crop&auto=format','1910년 파리의 한 카페 메뉴에 처음 등장한 크로크무슈는 프랑스 전역의 비스트로와 카페에서 필수 메뉴가 되었습니다.','Brunch',1),(64,'토스트','갓 구운 식빵과 버터의 소박하지만 완벽한 한 끼',3800,0,0,0,'DESSERT','https://images.unsplash.com/photo-1484723091739-30a097e8f929?w=600&h=400&fit=crop&auto=format','갓 구운 식빵의 따뜻한 온기와 버터가 녹아드는 순간의 소박한 행복을 담은 토스트는 언제나 옳은 선택입니다.','Brunch',1),(65,'샐러드','제철 유기농 채소와 견과류로 구성된 가벼운 한 끼',5000,0,0,0,'DESSERT','https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=600&h=400&fit=crop&auto=format','제철 유기농 채소와 견과류, 신선한 드레싱으로 구성된 우리의 샐러드는 가볍지만 충분한 한 끼를 약속합니다.','Brunch',1),(178,'아인슈페너','진한 에스프레소 위에 휘핑크림을 올린 비엔나 커피',5500,500,500,1000,'COFFEE','/images/einspanner.jpg','아인슈페너(Einspänner)는 19세기 오스트리아 비엔나에서 마부들이 마차 위에서 간편하게 마시던 커피입니다. 진한 에스프레소 위에 달콤한 휘핑크림을 얹어 마시는 것이 특징입니다.','HOT/ICE',1),(179,'시그니처라떼','파나마 게이샤 원두로 만든 로운카페 대표 라떼',6000,500,500,1000,'COFFEE','','로운카페만의 특별한 레시피로 탄생한 시그니처 라떼입니다. 파나마 게이샤 원두의 화사한 과일향과 부드러운 스팀 밀크가 어우러져 한 잔에 담긴 특별한 경험을 선사합니다.','HOT/ICE',1);
